{
    "level": "B1–B2",
    "intro": "In this topic you will learn <strong>advanced structures</strong> for emphasis: inversion with negative adverbs, cleft sentences and emphatic do.",
    "rules": [
        {
            "label": "Inversion",
            "color": "emerald",
            "text": "Negative adverb + <strong>Auxiliary + Subject</strong>:",
            "example": "Never have I seen such beauty."
        },
        {
            "label": "It-cleft",
            "color": "blue",
            "text": "<strong>It was/is ... who/that</strong> — reinforcement element:",
            "example": "It was you who invited me."
        },
        {
            "label": "What-cleft",
            "color": "amber",
            "text": "<strong>What ... is/was</strong> — reinforcement of action:",
            "example": "What I need is some rest."
        }
    ]
}

{
    "title": "1. When to use emphasis",
    "intro": "Emphatic structures are used to:",
    "items": [
        {
            "label": "1",
            "title": "Highlight information",
            "subtitle": "Emphasize who, what, when, where."
        },
        {
            "label": "2",
            "title": "Formal style",
            "subtitle": "In written, formal language."
        },
        {
            "label": "3",
            "title": "Contrast",
            "subtitle": "Contrast or correction."
        }
    ]
}

{
    "title": "2. Inversion with negative adverbs",
    "sections": [
        {
            "label": "Inversion structure",
            "color": "emerald",
            "description": "When a sentence begins with a <strong>negative adverb</strong>, the word order changes: <strong>Auxiliary + Subject</strong>.",
            "examples": [
                {
                    "en": "Never have I seen such a beautiful sunset.",
                    "ua": "Never have I seen such a beautiful sunset. saw such a sunset."
                },
                {
                    "en": "Rarely does she make mistakes.",
                    "ua": "She is rarely wrong."
                },
                {
                    "en": "Seldom do we get such opportunities.",
                    "ua": "Rarely do we get such opportunities."
                }
            ]
        },
        {
            "label": "Not only ... but also",
            "color": "sky",
            "description": "After <strong>Not only</strong> the inversion in the first parts.",
            "examples": [
                {
                    "en": "Not only did he finish early, but he also helped others.",
                    "ua": "He not only finished early, but also helped others."
                },
                {
                    "en": "Not only is she smart, but she is also kind.",
                    "ua": "She is not only smart, but also kind."
                }
            ]
        },
        {
            "label": "Hardly / No sooner",
            "color": "amber",
            "description": "Hardly had we arrived when it started raining.",
            "examples": [
                {
                    "en": "Hardly had we arrived when it started raining.",
                    "ua": "Hardly had we arrived when it started raining."
                },
                {
                    "en": "No sooner had I sat down than the phone rang.",
                    "ua": "I had just sat down when the phone rang."
                }
            ],
            "note": "Hardly/Scarcely + when; No sooner + than."
        }
    ]
}

{
    "title": "3. It-cleft sentence",
    "sections": [
        {
            "label": "Strengthening the person (who)",
            "color": "emerald",
            "description": "The structure <strong>It was/is + person + who</strong> reinforces who performed the action.",
            "examples": [
                {
                    "en": "You invited me. → It was you who invited me.",
                    "ua": "It was you who invited me."
                },
                {
                    "en": "She broke the vase. → It was she who broke the vase.",
                    "ua": "It was she who broke the vase."
                },
                {
                    "en": "John called. It was John who called. → It was yesterday that she left.",
                    "ua": "Саме Джон телефонував."
                }
            ]
        },
        {
            "label": "Підсилення часу/місця/об'єкта (that)",
            "color": "sky",
            "description": "Структура <strong>It was/is + element + that</strong> для підсилення не-осіб.",
            "examples": [
                {
                    "en": "She left yesterday. → It was yesterday that she left.",
                    "ua": "It was yesterday that she left."
                },
                {
                    "en": "I need help. → It is help that I need.",
                    "ua": "It is help that I need."
                },
                {
                    "en": "We met in Paris. → It was in Paris that we met.",
                    "ua": "It was in Paris that we met."
                }
            ],
            "note": "For people - who, for the rest - that."
        }
    ]
}

{
    "title": "4. What-cleft sentence (Pseudo-cleft)",
    "sections": [
        {
            "label": "What-cleft structure",
            "color": "emerald",
            "description": "<strong>What + clause + is/was + emphasized element</strong> — strengthens the action or object.",
            "examples": [
                {
                    "en": "I need rest. → What I need is some rest.",
                    "ua": "What I need is some rest."
                },
                {
                    "en": "I like the park. → What I like is the park.",
                    "ua": "What I like is the park."
                },
                {
                    "en": "She wants a vacation. → What she wants is a vacation.",
                    "ua": "What she wants is a vacation."
                }
            ]
        },
        {
            "label": "Other Wh-cleft structures",
            "color": "sky",
            "description": "You can use <strong>Where, Why, Who, How</strong> for different types of reinforcement.",
            "examples": [
                {
                    "en": "Where I grew up is very far from here.",
                    "ua": "Where I grew up is very far from here."
                },
                {
                    "en": "Why she left is still a mystery.",
                    "ua": "Why she left is still a mystery."
                },
                {
                    "en": "How he did it amazed everyone.",
                    "ua": "How he did it surprised everyone."
                }
            ]
        }
    ]
}

{
    "title": "5. Fronting and Emphatic do",
    "sections": [
        {
            "label": "Fronting",
            "color": "emerald",
            "description": "<strong>Fronting</strong> — placing an element at the beginning of a sentence for emphasis or contrast.",
            "examples": [
                {
                    "en": "The kids left quickly. → Quickly the kids left.",
                    "ua": "Quickly the kids left."
                },
                {
                    "en": "I like this book very much. → This book I like very much.",
                    "ua": "This book I like very much."
                },
                {
                    "en": "Away ran the children.",
                    "ua": "Away ran the children."
                }
            ],
            "note": "Often used in literature and formal English."
        },
        {
            "label": "Emphatic do/does/did",
            "color": "sky",
            "description": "For emphasis in <strong>affirmative</strong> sentences, use do/does/did with with emphasis.",
            "examples": [
                {
                    "en": "I like it. → I DO like it!",
                    "ua": "I really like it!"
                },
                {
                    "en": "She finished. → She DID finish her homework!",
                    "ua": "She did do her homework!"
                },
                {
                    "en": "He knows. → He DOES know the answer.",
                    "ua": "He really knows the answer."
                }
            ],
            "note": "Often used colloquially to confirm."
        }
    ]
}

{
    "title": "6. Negative adverbs for inversion",
    "intro": "Remember these expressions - they must be followed by inversion:",
    "rows": [
        {
            "en": "Never",
            "ua": "never",
            "note": "Never have I..."
        },
        {
            "en": "Rarely / Seldom",
            "ua": "rarely",
            "note": "Rarely does she..."
        },
        {
            "en": "Hardly / Scarcely",
            "ua": "barely",
            "note": "Hardly had we..."
        },
        {
            "en": "Not only",
            "ua": "not only",
            "note": "Not only did he..."
        },
        {
            "en": "No sooner",
            "ua": "just",
            "note": "No sooner had I..."
        },
        {
            "en": "Only when/after/if[[[CODX_30]]]only when/after/if[[[CODX_SEG_31]]Only] when I arrived did I...",
            "ua": "тільки коли/після/якщо",
            "note": "Only when I arrived did I..."
        }
    ],
    "warning": "📌 If there is no auxiliary verb - add do/does/did."
}

{
    "title": "7. Typical mistakes of Ukrainian speakers",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Missing inversion after a negative adverb.",
            "wrong": "Never I have seen...",
            "right": " ✅ <span class="font-mono">Never have I seen...</span>[[[CODX_3]]]Error 2"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Which instead of who people.",
            "wrong": "It was you which invited me.[[[CODX_6]]]​​​​ <span class="font-mono">It was you who invited me.</span>",
            "right": "✅ <span class="font-mono">It was you who invited me.</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Infinitive instead of noun in What-cleft.[[[CODX_9]]]What I need is to rest.",
            "wrong": "What I need is to rest.",
            "right": "​​​​​​​​​​ the answer.</span>"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Дієслово з -s після emphatic do.",
            "wrong": "He do knows the answer.",
            "right": "✅ <span class="font-mono">He does know the answer.</span>"
        }
    ]
}

{
    "title": "9. Practice",
    "select_title": "Exercise 1. Choose the correct option",
    "select_intro": "Choose sentences with the correct structure.",
    "selects": [
        {
            "label": "a) Never I have seen... / b) Never have I seen...",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) It was you who invited me. / b) It was you which invited me.",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) What I need is some rest. / b) What I needed is to rest. →",
            "prompt": "Який варіант правильний?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Вправа 2. Перетвори на It-cleft",
    "input_intro": "Підсиль виділений елемент за допомогою It-cleft.",
    "inputs": [
        {
            "before": "YOU called me. →",
            "after": "It was..."
        },
        {
            "before": "She left YESTERDAY. →",
            "after": "It was..."
        },
        {
            "before": "I need HELP. It is... beauty.",
            "after": "It is..."
        }
    ],
    "rephrase_title": "Вправа 3. Додай інверсію",
    "rephrase_intro": "Перетвори речення, починаючи з негативного прислівника.",
    "rephrase": [
        {
            "example_label": "Приклад:",
            "example_original": "I have never seen such beauty.",
            "example_target": "Never have I seen such beauty."
        },
        {
            "original": "1. She rarely makes mistakes.",
            "placeholder": "Rarely..."
        },
        {
            "original": "2. He not only finished early but also helped. Adverbs and Circumstances",
            "placeholder": "Not only..."
        }
    ]
}

{
