            "label": "Word Order with Adverbs — Прислівники та обставини",
            "current": false
        },
        {
            "label": "Word Order with Verbs and Objects - Verbs and Attachments",
            "current": false
        },
        {
            "label": "Advanced Word Order - Inversion and Strengthening (current)",
            "current": true
        }
    ]
}
